// ========== Helper Functions ==========

/** Convert SVG string to data URI. PNG constants already arrive as data URIs. */
function svgToDataUri(svg: string): string {
  const encoded = encodeURIComponent(svg).replace(/'/g, "%27").replace(/"/g, "%22");
  return `data:image/svg+xml,${encoded}`;
}

// ========== Badge Map ==========

/**
 * Map of badge type to bundled data URI.
 * All sub-gifter tier aliases (subgifter5, 25, 50, 100, 200) point to the
 * same single PNG since id3adeye/kickicons ships one canonical icon.
 * Tooltip rendering surfaces the gift COUNT via the badge title in
 * kick-parser.parseKickBadges.
 */
export const KICK_BUNDLED_BADGES: Record<string, string> = {
  bot: BOT_PNG,
  broadcaster: BROADCASTER_PNG,
  founder: FOUNDER_PNG,
  moderator: MODERATOR_PNG,
  og: OG_PNG,
  vip: VIP_PNG,
  verified: VERIFIED_PNG,
  sub_gifter: SUB_GIFTER_PNG,
  subgifter: SUB_GIFTER_PNG,
  subgifter5: SUB_GIFTER_PNG,
  subgifter25: SUB_GIFTER_PNG,
  subgifter50: SUB_GIFTER_PNG,
  subgifter100: SUB_GIFTER_PNG,
  subgifter200: SUB_GIFTER_PNG,
  subscriber: svgToDataUri(SUBSCRIBER_SVG),
  staff: svgToDataUri(STAFF_SVG),
  sidekick: svgToDataUri(SIDEKICK_SVG),
};

/**
 * Get bundled badge URL by badge type
 * Returns undefined if badge type is not found
 */
export function getBundledBadgeUrl(badgeType: string): string | undefined {
  const normalized = badgeType.toLowerCase().replace(/[-\s]/g, "_");
  return KICK_BUNDLED_BADGES[normalized];
}

/**
 * Check if a badge type has a bundled version
 */
export function hasBundledBadge(badgeType: string): boolean {
  const normalized = badgeType.toLowerCase().replace(/[-\s]/g, "_");
  return normalized in KICK_BUNDLED_BADGES;
}
